const budget   = $('Supabase — Budget del mes anterior').first()?.json;
const expenses = $('Supabase — Gastos del mes anterior').all();
const user     = $('Supabase — Usuarios Plus activos').first().json;

if (!budget) return [];  // Usuario no tuvo presupuesto el mes pasado

// Agrupar gastos por categoría
const byCategory = {};
for (const exp of expenses) {
  const cat = exp.json.category;
  if (!byCategory[cat]) byCategory[cat] = 0;
  byCategory[cat] += Number(exp.json.amount);
}

// Calcular totales
const total_spent  = Object.values(byCategory).reduce((a, b) => a + b, 0);
const income       = Number(budget.income);
const savings      = Math.max(income - total_spent, 0);
const savings_rate = income > 0 ? Math.round((savings / income) * 100) : 0;

// Categoría con mayor gasto
const top_category = Object.entries(byCategory)
  .sort((a, b) => b[1] - a[1])[0];

// Mes anterior formateado
const prev = new Date();
prev.setMonth(prev.getMonth() - 1);
const month_name = prev.toLocaleDateString('es-AR', { month: 'long', year: 'numeric' });

return [{
  json: {
    user_id:      user.id,
    month_name,
    income,
    total_spent,
    savings,
    savings_rate,
    by_category:  byCategory,
    top_category: top_category ? { name: top_category[0], amount: top_category[1] } : null,
    budget_month: budget.month
  }
}];

