const response = $input.first().json;
const text = response.content[0].text;

try {
  const parsed = JSON.parse(text);
  const user_data = $('Preparar datos para Claude').first().json;

  return parsed.insights.map((insight, i) => ({
    json: {
      user_id:    user_data.user_id,
      month:      user_data.budget_month,
      type:       insight.type,
      title:      insight.title,
      body:       insight.body,
      sort_order: i + 1,
      created_at: new Date().toISOString()
    }
  }));
} catch (e) {
  // Si Claude no devolvió JSON válido, logeamos el error
  console.error('Error parsing Claude response:', text);
  return [];
}
